import React, { useState, useRef } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useTheme } from '../../context/ThemeContext';
import API, { authAPI } from '../../utils/api';
import { PageHeader, Card, Button, Input, Textarea, Select } from '../../components/common/UI';
import { FiUser, FiLock, FiSettings, FiCamera, FiVolume2, FiCheckCircle } from 'react-icons/fi';
import toast from 'react-hot-toast';
import { playSound } from '../../utils/soundEffects';

export default function Settings() {
  const { user, updateUser } = useAuth();
  const { isDark, toggleTheme, accentColor, setAccentColor, density, setDensity } = useTheme();

  const [soundEnabled, setSoundEnabled] = useState(() => localStorage.getItem('fh_sound_enabled') !== 'false');
  const [toastEnabled, setToastEnabled] = useState(() => localStorage.getItem('fh_toast_enabled') !== 'false');
  const [soundType, setSoundType] = useState(() => localStorage.getItem('fh_sound_type') || 'chime');

  const [activeTab, setActiveTab] = useState('profile');
  const [savingProfile, setSavingProfile] = useState(false);
  const [savingPassword, setSavingPassword] = useState(false);

  // Profile form
  const [profileForm, setProfileForm] = useState({
    name: user?.name || '',
    mobile: user?.mobile || '',
    bio: user?.bio || '',
    skills: user?.skills?.join(', ') || ''
  });
  const [avatarFile, setAvatarFile] = useState(null);
  const [avatarPreview, setAvatarPreview] = useState(null);
  const avatarRef = useRef();

  // Password form
  const [pwdForm, setPwdForm] = useState({
    currentPassword: '',
    newPassword: '',
    confirm: ''
  });

  const handleAvatar = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 10 * 1024 * 1024) {
      toast.error('Image must be under 10MB');
      return;
    }
    setAvatarFile(file);
    setAvatarPreview(URL.createObjectURL(file));
  };

  const handleSaveProfile = async (e) => {
    e.preventDefault();
    setSavingProfile(true);
    try {
      const formData = new FormData();
      formData.append('name', profileForm.name);
      formData.append('mobile', profileForm.mobile);
      formData.append('bio', profileForm.bio);
      formData.append('skills', profileForm.skills);
      if (avatarFile) {
        formData.append('image', avatarFile);
      }

      const res = await authAPI.updateProfile(formData);
      updateUser(res.data.user);
      toast.success('Profile settings updated!');
      setAvatarFile(null);
      setAvatarPreview(null);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to update profile.');
    }
    setSavingProfile(false);
  };

  const handleSavePassword = async (e) => {
    e.preventDefault();
    if (pwdForm.newPassword.length < 8) {
      toast.error('New password must be at least 8 characters.');
      return;
    }
    if (pwdForm.newPassword !== pwdForm.confirm) {
      toast.error('Passwords do not match.');
      return;
    }
    setSavingPassword(true);
    try {
      await authAPI.changePassword({
        currentPassword: pwdForm.currentPassword,
        newPassword: pwdForm.newPassword
      });
      toast.success('Password updated successfully!');
      setPwdForm({ currentPassword: '', newPassword: '', confirm: '' });
    } catch (err) {
      toast.error(err.response?.data?.message || 'Password update failed.');
    }
    setSavingPassword(false);
  };

  const initials = user?.name?.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2) || 'U';

  const tabs = [
    { id: 'profile', label: 'Profile Info', icon: FiUser },
    { id: 'security', label: 'Security', icon: FiLock },
    { id: 'preferences', label: 'Preferences', icon: FiSettings }
  ];

  return (
    <div>
      <PageHeader title="Account Settings" subtitle="Configure your profile, preferences, and system parameters." />

      <div className="flex flex-col md:flex-row gap-6 p-6 max-w-5xl">
        {/* Sidebar Tabs */}
        <div className="w-full md:w-60 flex-shrink-0 flex flex-col gap-1">
          {tabs.map((tab) => {
            const Icon = tab.icon;
            const isActive = activeTab === tab.id;
            return (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`flex items-center gap-2.5 px-4 py-3 rounded-lg text-sm font-medium transition-all text-left ${
                  isActive
                    ? 'bg-neon/10 text-neon-light'
                    : 'text-text-secondary hover:bg-bg-surface-2 hover:text-text-primary'
                }`}
                style={isActive ? { borderLeft: '3px solid var(--neon)' } : {}}
              >
                <Icon size={16} />
                <span>{tab.label}</span>
              </button>
            );
          })}
        </div>

        {/* Tab Contents */}
        <div className="flex-1 min-w-0">
          {activeTab === 'profile' && (
            <Card>
              <h2 className="font-display font-bold text-base mb-4" style={{ color: 'var(--text-primary)' }}>Profile Settings</h2>
              <form onSubmit={handleSaveProfile} className="space-y-4">
                <div className="flex items-center gap-4 mb-6">
                  <div className="relative">
                    {avatarPreview || user?.profileImage ? (
                      <img src={avatarPreview || user.profileImage} alt="avatar" className="w-20 h-20 rounded-full object-cover border-2 border-border" />
                    ) : (
                      <div className="w-20 h-20 rounded-full flex items-center justify-center text-white text-2xl font-bold"
                        style={{ background: 'linear-gradient(135deg, var(--neon), var(--purple))' }}>{initials}</div>
                    )}
                    <button
                      type="button"
                      onClick={() => avatarRef.current?.click()}
                      className="absolute -bottom-1 -right-1 w-8 h-8 rounded-full flex items-center justify-center text-white"
                      style={{ background: 'var(--neon)', border: '2px solid var(--bg-secondary)' }}
                      title="Change photo"
                    >
                      <FiCamera size={14} />
                    </button>
                    <input ref={avatarRef} type="file" accept="image/*" className="hidden" onChange={handleAvatar} />
                  </div>
                  <div className="text-xs" style={{ color: 'var(--text-muted)' }}>
                    PNG, JPG, WebP image formats supported.<br />
                    Maximum file upload size limit is 10MB.
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <Input
                    label="Full Name"
                    required
                    value={profileForm.name}
                    onChange={(e) => setProfileForm({ ...profileForm, name: e.target.value })}
                  />
                  <Input
                    label="Mobile Number"
                    required
                    value={profileForm.mobile}
                    onChange={(e) => setProfileForm({ ...profileForm, mobile: e.target.value })}
                  />
                </div>

                <Textarea
                  label="Biography"
                  rows={3}
                  value={profileForm.bio}
                  onChange={(e) => setProfileForm({ ...profileForm, bio: e.target.value })}
                  placeholder="Describe your freelance background, skills, or portfolio..."
                />

                <Input
                  label="Skills (Comma-separated tags)"
                  value={profileForm.skills}
                  onChange={(e) => setProfileForm({ ...profileForm, skills: e.target.value })}
                  placeholder="e.g. React, Node.js, Graphic Design, Copywriting"
                />

                <div className="pt-2 flex justify-end">
                  <Button type="submit" loading={savingProfile}>Save Settings</Button>
                </div>
              </form>
            </Card>
          )}

          {activeTab === 'security' && (
            <Card>
              <h2 className="font-display font-bold text-base mb-4" style={{ color: 'var(--text-primary)' }}>Password & Security</h2>
              <form onSubmit={handleSavePassword} className="space-y-4">
                <Input
                  label="Current Password"
                  type="password"
                  required
                  value={pwdForm.currentPassword}
                  onChange={(e) => setPwdForm({ ...pwdForm, currentPassword: e.target.value })}
                />
                <Input
                  label="New Password"
                  type="password"
                  required
                  placeholder="At least 8 characters"
                  value={pwdForm.newPassword}
                  onChange={(e) => setPwdForm({ ...pwdForm, newPassword: e.target.value })}
                />
                <Input
                  label="Confirm New Password"
                  type="password"
                  required
                  value={pwdForm.confirm}
                  onChange={(e) => setPwdForm({ ...pwdForm, confirm: e.target.value })}
                />

                <div className="pt-2 flex justify-end">
                  <Button type="submit" loading={savingPassword}>Update Password</Button>
                </div>
              </form>
            </Card>
          )}

          {activeTab === 'preferences' && (
            <Card>
              <h2 className="font-display font-bold text-base mb-4" style={{ color: 'var(--text-primary)' }}>Visual & Notification Preferences</h2>
              <div className="space-y-6">

                {/* 1. Theme Mode */}
                <div>
                  <label className="block text-xs font-semibold mb-2" style={{ color: 'var(--text-secondary)' }}>Color Theme Mode</label>
                  <div className="flex gap-4">
                    <button
                      type="button"
                      onClick={() => !isDark && toggleTheme()}
                      className={`flex-1 p-3 rounded-lg border text-center transition-all text-sm font-medium ${
                        isDark ? 'border-neon bg-neon/10 text-neon-light' : 'border-border text-text-secondary'
                      }`}
                    >
                      🌌 Dark Mode
                    </button>
                    <button
                      type="button"
                      onClick={() => isDark && toggleTheme()}
                      className={`flex-1 p-3 rounded-lg border text-center transition-all text-sm font-medium ${
                        !isDark ? 'border-neon bg-neon/10 text-neon-light' : 'border-border text-text-secondary'
                      }`}
                    >
                      ☀️ Light Mode
                    </button>
                  </div>
                </div>

                {/* 2. Theme Accent Color Selector */}
                <div className="pt-4 border-t" style={{ borderColor: 'var(--border)' }}>
                  <label className="block text-xs font-semibold mb-2" style={{ color: 'var(--text-secondary)' }}>Interface Accent Color</label>
                  <div className="flex flex-wrap gap-3">
                    {[
                      { id: 'blue', name: 'Neon Blue', color: '#3b82f6' },
                      { id: 'purple', name: 'Purple Glow', color: '#8b5cf6' },
                      { id: 'green', name: 'Emerald Green', color: '#10b981' },
                      { id: 'amber', name: 'Sunset Amber', color: '#f59e0b' },
                      { id: 'rose', name: 'Rose Pink', color: '#ec4899' }
                    ].map((item) => {
                      const isActive = accentColor === item.id;
                      return (
                        <button
                          key={item.id}
                          type="button"
                          onClick={() => setAccentColor(item.id)}
                          className={`flex items-center gap-2 px-3 py-2 rounded-lg border text-sm font-medium transition-all ${
                            isActive ? 'border-neon bg-neon/10 text-neon-light' : 'border-border text-text-secondary hover:text-text-primary'
                          }`}
                        >
                          <span
                            className="w-3.5 h-3.5 rounded-full inline-block border"
                            style={{ backgroundColor: item.color, borderColor: 'rgba(255,255,255,0.2)' }}
                          />
                          <span>{item.name}</span>
                          {isActive && <FiCheckCircle className="ml-1 text-neon-light" size={13} />}
                        </button>
                      );
                    })}
                  </div>
                </div>

                {/* 3. Spacing Layout Density */}
                <div className="pt-4 border-t" style={{ borderColor: 'var(--border)' }}>
                  <label className="block text-xs font-semibold mb-2" style={{ color: 'var(--text-secondary)' }}>Spacing Layout Density</label>
                  <div className="flex gap-4">
                    <button
                      type="button"
                      onClick={() => setDensity('standard')}
                      className={`flex-1 p-3 rounded-lg border text-center transition-all text-sm font-medium ${
                        density === 'standard' ? 'border-neon bg-neon/10 text-neon-light' : 'border-border text-text-secondary'
                      }`}
                    >
                      📏 Standard Spacing
                    </button>
                    <button
                      type="button"
                      onClick={() => setDensity('compact')}
                      className={`flex-1 p-3 rounded-lg border text-center transition-all text-sm font-medium ${
                        density === 'compact' ? 'border-neon bg-neon/10 text-neon-light' : 'border-border text-text-secondary'
                      }`}
                    >
                      🗜️ Compact Spacing
                    </button>
                  </div>
                </div>

                {/* 4. Audio & Notification Toggles */}
                <div className="pt-4 border-t" style={{ borderColor: 'var(--border)' }}>
                  <label className="block text-xs font-semibold mb-2" style={{ color: 'var(--text-secondary)' }}>Alerts & Notifications</label>
                  <div className="space-y-4">
                    <label className="flex items-center gap-2.5 text-sm cursor-pointer">
                      <input
                        type="checkbox"
                        checked={soundEnabled}
                        onChange={(e) => {
                          const val = e.target.checked;
                          setSoundEnabled(val);
                          localStorage.setItem('fh_sound_enabled', val ? 'true' : 'false');
                          if (val) playSound(soundType);
                        }}
                        className="rounded border-border text-neon focus:ring-neon bg-bg-surface-2"
                      />
                      <span style={{ color: 'var(--text-secondary)' }}>Play notification sound on new activity alerts</span>
                    </label>

                    <label className="flex items-center gap-2.5 text-sm cursor-pointer">
                      <input
                        type="checkbox"
                        checked={toastEnabled}
                        onChange={(e) => {
                          const val = e.target.checked;
                          setToastEnabled(val);
                          localStorage.setItem('fh_toast_enabled', val ? 'true' : 'false');
                        }}
                        className="rounded border-border text-neon focus:ring-neon bg-bg-surface-2"
                      />
                      <span style={{ color: 'var(--text-secondary)' }}>Show pop-up toast alerts in bottom-right corner</span>
                    </label>

                    <div className="flex flex-col sm:flex-row gap-3 pt-2">
                      <div className="flex-1">
                        <label className="block text-xs font-semibold mb-1.5" style={{ color: 'var(--text-secondary)' }}>Notification Sound Effect</label>
                        <select
                          value={soundType}
                          onChange={(e) => {
                            const val = e.target.value;
                            setSoundType(val);
                            localStorage.setItem('fh_sound_type', val);
                            if (soundEnabled) playSound(val);
                          }}
                          disabled={!soundEnabled}
                          className="w-full bg-bg-surface-2 border border-border rounded-lg p-2 text-sm text-text-primary focus:outline-none focus:border-neon disabled:opacity-50"
                        >
                          <option value="chime">🎵 Elegant Chime</option>
                          <option value="blip">⚡ Retro Blip</option>
                          <option value="tap">🔨 Subtle Tap</option>
                        </select>
                      </div>
                      <button
                        type="button"
                        onClick={() => playSound(soundType)}
                        disabled={!soundEnabled}
                        className="btn-ghost flex items-center justify-center gap-2 py-2 px-4 rounded-lg mt-0 sm:mt-5 text-sm disabled:opacity-50"
                        title="Play Preview"
                      >
                        <FiVolume2 size={16} />
                        <span>Play Preview</span>
                      </button>
                    </div>

                    <div className="pt-2">
                      <button
                        type="button"
                        onClick={() => {
                          if (toastEnabled) {
                            toast.success('Visual preview of bottom-right toast notifications!');
                          } else {
                            toast('Notification sound demo (Toasts disabled)', { icon: '🔔' });
                          }
                          if (soundEnabled) playSound(soundType);
                        }}
                        className="btn-ghost text-xs py-1.5 px-3 rounded"
                      >
                        ✨ Test Notification Trigger
                      </button>
                    </div>
                  </div>
                </div>

              </div>
            </Card>
          )}


        </div>
      </div>
    </div>
  );
}
